// Parse the extractor's JSON, validate the groundedness contract, and count.
// Any requirement without a verbatim quote is dropped and logged - this is the
// quote-or-it-doesn't-exist rule enforced in code rather than left to the model.

const raw = $input.first().json;
let text = raw.text ?? raw.output ?? raw.response ?? '';
if (typeof text === 'object') text = JSON.stringify(text);

// tolerate ```json fences
text = String(text).replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();

let ex;
try {
  ex = JSON.parse(text);
} catch (e) {
  throw new Error('Extractor did not return valid JSON. Raw output: ' + text.slice(0, 500));
}

const arr = (k) => Array.isArray(ex[k]) ? ex[k] : [];
const hasQuote = (o) => typeof o.quote === 'string' && o.quote.trim().length > 0;

// Groundedness gate: drop unsupported items, keep them for the trace.
const dropped = [];
const stated = arr('stated_requirements').filter(r => {
  if (!hasQuote(r)) { dropped.push({ where: 'stated_requirements', item: r }); return false; }
  return true;
});
const personas = arr('personas').filter(p => {
  if (!hasQuote(p)) { dropped.push({ where: 'personas', item: p }); return false; }
  return true;
});

const extraction = {
  ...ex,
  stated_requirements: stated,
  personas: personas,
};

return [{
  json: {
    input_text: $('Prepare Chat Input').first().json.input_text,
    test_id: $('Prepare Chat Input').first().json.test_id,
    extraction,
    gaps: {
      ambiguous_items: arr('ambiguous_items'),
      contradictions: arr('contradictions'),
      not_discussed: arr('not_discussed'),
      missing_information: arr('missing_information'),
      stakeholders: arr('stakeholders'),
    },
    stated_count: stated.length,
    ambiguous_count: arr('ambiguous_items').length,
    contradiction_count: arr('contradictions').length,
    input_assessment: ex.input_assessment ?? 'UNKNOWN',
    unsupported_items_dropped: dropped.length,
    dropped_items: dropped,
  }
}];

// Reach back to the source nodes for identity and metrics rather than relying on
// them surviving the trip through the LLM chain nodes - chainLlm returns only
// {text}, so anything not explicitly re-attached is dropped.
const src  = $('Prepare Chat Input').first().json;
const meta = $('Parse + Validate Extraction').first().json;

const items = $input.all().map(i => i.json);
const pick = (k) => {
  for (const i of items) {
    const v = i[k];
    if (typeof v === 'string' && v.trim()) return v;
  }
  return '';
};

// Filesystem-safe. A fallback containing '/' would be read by n8n as a path
// separator and silently split the filename.
const testId = String(src.test_id ?? 'unknown').replace(/[^A-Za-z0-9._-]/g, '_');

return [{
  json: {
    test_id: testId,
    input_assessment: meta.input_assessment ?? 'UNKNOWN',
    stated_count: meta.stated_count ?? 0,
    ambiguous_count: meta.ambiguous_count ?? 0,
    contradiction_count: meta.contradiction_count ?? 0,
    unsupported_items_dropped: meta.unsupported_items_dropped ?? 0,
    halted_at_sufficiency_gate: items.some(i => i.halted_at_sufficiency_gate === true),
    prd_markdown: pick('prd_markdown'),
    stories_markdown: pick('stories_markdown'),
    gap_markdown: pick('gap_markdown'),
  }
}];

// Chat Trigger gives us { chatInput, sessionId }. Normalise it into the shape the
// rest of the pipeline already expects, so no downstream node had to change.
const j = $input.first().json;
const raw = String(j.chatInput ?? j.text ?? '').trim();

// An optional "T1: ..." prefix tags the run without changing behaviour, which keeps
// the baseline test dataset runnable straight from the chat box.
const m = raw.match(/^\s*(T\d{1,2})\s*[:.\-]\s*([\s\S]+)$/i);
const test_id    = m ? m[1].toUpperCase() : 'chat';
const input_text = m ? m[2].trim() : raw;

if (!input_text) {
  throw new Error('No text received. Paste a transcript, brief, or notes into the chat.');
}

return [{ json: { test_id, input_text, sessionId: j.sessionId ?? null } }];

// One chat message: the three deliverables, each under its own heading.
// The HTTP node upstream replaced the item with Langfuse's response,
// so reach back for the payload rather than reading $input.
const j = $('Assemble Submission Outputs').first().json;

const missing = (what) =>
  `_${what} not generated - the input did not contain enough stated requirements._`;

const prd     = (j.prd_markdown || '').trim() || missing('PRD');
const stories = (j.stories_markdown || '').trim() ||
                (j.halted_at_sufficiency_gate
                  ? '_No user stories - no PRD was generated for this input._'
                  : missing('User stories'));
const gaps    = (j.gap_markdown || '').trim() || missing('Clarification questions');

// Demote headings inside each section by one level so the three section headings
// stay the outermost structure instead of competing with the agents' own headings.
const demote = (md) => md.replace(/^(#{1,5}) /gm, '$1# ');

const header = j.halted_at_sufficiency_gate
  ? '> **No PRD generated.** The extractor found no stated requirements in this input, so the PRD Generator was never invoked. The questions below are what to take back to stakeholders.'
  : `> **${j.stated_count}** stated requirement(s) · **${j.ambiguous_count}** ambiguous · **${j.contradiction_count}** contradiction(s)` +
    (j.unsupported_items_dropped ? ` · **${j.unsupported_items_dropped}** unsupported item(s) dropped` : '');

const output = [
  '# PRD Genie' + (j.test_id && j.test_id !== 'chat' ? ' — ' + j.test_id : ''),
  '',
  header,
  '',
  '---',
  '',
  '# 1. Product Requirements Document',
  '',
  demote(prd),
  '',
  '---',
  '',
  '# 2. Epics and User Stories',
  '',
  demote(stories),
  '',
  '---',
  '',
  '# 3. Clarification Questions',
  '',
  demote(gaps),
].join('\n');

// The Chat Trigger renders the last node's `output` field as the reply.
return [{ json: {
  output,
  test_id: j.test_id,
  stated_count: j.stated_count,
  ambiguous_count: j.ambiguous_count,
  contradiction_count: j.contradiction_count,
  unsupported_items_dropped: j.unsupported_items_dropped,
  halted_at_sufficiency_gate: j.halted_at_sufficiency_gate,
} }];

// Build a Langfuse ingestion batch: one trace, the agent generations, and two
// spans for the guardrails. The guardrail spans are the reason to do this by hand
// rather than infer the gate from which generations are absent.

const asm  = $input.first().json;
const src  = $('Prepare Chat Input').first().json;
const meta = $('Parse + Validate Extraction').first().json;

// Self-contained UUID: the Code sandbox does not reliably expose crypto.
const uid = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
  const r = Math.random() * 16 | 0;
  return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
});

const t0 = Date.now();
const iso = (ms = 0) => new Date(t0 + ms).toISOString();
const traceId = uid();
const batch = [];
const push = (type, body) => batch.push({ id: uid(), type, timestamp: iso(), body });

// Estimate only - see 07-langfuse-integration.md before using these for cost.
const est = (s) => Math.ceil(String(typeof s === 'string' ? s : JSON.stringify(s ?? '')).length / 4);

push('trace-create', {
  id: traceId,
  name: 'PRD Genie',
  sessionId: src.sessionId ?? undefined,
  input: src.input_text,
  output: asm.prd_markdown,
  tags: [asm.test_id, asm.input_assessment,
         asm.halted_at_sufficiency_gate ? 'halted' : 'completed'].filter(Boolean),
  metadata: {
    test_id: asm.test_id,
    stated_count: asm.stated_count,
    ambiguous_count: asm.ambiguous_count,
    contradiction_count: asm.contradiction_count,
    unsupported_items_dropped: asm.unsupported_items_dropped,
    halted_at_sufficiency_gate: asm.halted_at_sufficiency_gate,
  },
});

const generation = (name, model, input, output, offset) => {
  push('generation-create', {
    id: uid(), traceId, name, model,
    startTime: iso(offset), endTime: iso(offset + 1000),
    modelParameters: { temperature: 0 },
    input, output,
    usageDetails: { input: est(input), output: est(output),
                    total: est(input) + est(output) },
  });
};

generation('Agent 1 · Requirement Extractor', 'gpt-4o-mini',
           src.input_text, meta.extraction, 0);

if (!asm.halted_at_sufficiency_gate) {
  generation('Agent 2 · PRD Generator', 'gpt-4o',
             meta.extraction, asm.prd_markdown, 2000);
  generation('Agent 3 · Story Breakdown', 'gpt-4o',
             asm.prd_markdown, asm.stories_markdown, 4000);
}
generation('Agent 4 · Gap Analyzer', 'gpt-4o-mini',
           meta.gaps, asm.gap_markdown, 2000);

push('span-create', {
  id: uid(), traceId, name: 'Guardrail · quote validation',
  startTime: iso(1200), endTime: iso(1250),
  level: (asm.unsupported_items_dropped > 0) ? 'WARNING' : 'DEFAULT',
  statusMessage: `${asm.unsupported_items_dropped ?? 0} unsupported item(s) dropped`,
  input: { stated_items_kept: meta.stated_count ?? 0 },
  output: { dropped: meta.dropped_items ?? [] },
});

push('span-create', {
  id: uid(), traceId, name: 'Guardrail · sufficiency gate',
  startTime: iso(1300), endTime: iso(1350),
  level: asm.halted_at_sufficiency_gate ? 'WARNING' : 'DEFAULT',
  statusMessage: asm.halted_at_sufficiency_gate
    ? 'HALTED — no stated requirements; PRD Generator not invoked'
    : `PASSED — ${asm.stated_count} stated requirement(s)`,
  input: { stated_count: asm.stated_count ?? 0 },
  output: { proceeded: !asm.halted_at_sufficiency_gate },
});

return [{ json: { batch } }];
